// DMC Hospital Logo (base64-encoded for PDF/Print)
const DMC_LOGO_BASE64 = 'data:image/jpeg;base64,';

// Helper to get users who have actually recorded data (for audit filters)
function getKnownUsers() {
  const map = new Map();
  // Include standard predefined users first
  USERS.forEach(u => map.set(String(u.id), u));
  // Add any other users found in entries
  db_entries.forEach(e => {
    if (!e?.userId || !e?.userName) return;
    const cleanName = cleanEncoding(e.userName);
    if (!map.has(String(e.userId))) {
      map.set(String(e.userId), { id: e.userId, name: cleanName, role: 'user' });
    }
  });
  return Array.from(map.values()).sort((a, b) => a.name.localeCompare(b.name));
}

/**
 * FIX: Robust encoding cleanup to prevent "leaking" artifacts like ГғВўГўвӮ¬ ГўвҖҡВ¬
 */
function cleanEncoding(str) {
  if (typeof str !== 'string') return str;
  const replacements = {
    "ГғВўГўвӮ¬ ГўвҖҡВ¬": "в”Җ", "ГғВўвӮ¬ГўвҖҡВ¬": "в”Җ", "ГғВўГўвҖҡВ¬ГўвӮ¬Е“": "вҖ“", "ГӮВ·": "В·",
    "ГғВўГўвӮ¬ Гў": "в”Җ", "ГғВўГўвӮ¬": "в”Җ", "ГғВў": "в”Җ", "ГӮ": "", "ГўвҖҡВ¬": "вӮ¬",
    "ГўвӮ¬вҖң": "вҖ“", "ГўвӮ¬вҖқ": "вҖ”", "Гғ": "Г "
  };
  let result = str;
  Object.entries(replacements).forEach(([key, val]) => {
    result = result.split(key).join(val);
  });
  return result;
}

