function getCurrentShift(date = new Date()) {
  const h = date.getHours();
  // Morning: 10:00 (10am) to 19:00 (7pm). Night: 19:00 to 10:00.
  return (h >= 10 && h < 19) ? 'morning' : 'night';
}
function getShiftLabel(shift) {
  return shift === 'morning' ? 'вҳҖпёҸВҸ Morning Shift (10:00вҖ“19:00)' : 'рҹҢҷ Night Shift (19:00вҖ“10:00)';
}
function getShiftBadgeHTML(shift) {
  const cls = shift === 'morning' ? 'badge-amber' : 'badge-purple';
  const icon = shift === 'morning' ? 'fa-sun' : 'fa-moon';
  const label = shift === 'morning' ? 'Morning Shift' : 'Night Shift';
  return `<span class="badge ${cls}"><i class="fa-solid ${icon}"></i> ${label}</span>`;
}

// в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬ CLOCK в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬
let lastClockTime = '';
function startClock() {
  const clockEl = document.getElementById('clock-display');
  const shiftBadgeEl = document.getElementById('header-shift-badge');
  const sidebarShiftEl = document.getElementById('sidebar-shift');

  function tick() {
    const now = new Date();
    const time = now.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    const date = now.toLocaleDateString('en-GB', { weekday: 'short', day: '2-digit', month: 'short' });
    const fullTime = `${date} В· ${time}`;

    if (fullTime !== lastClockTime) {
      if (clockEl) clockEl.textContent = fullTime;
      lastClockTime = fullTime;

      const shift = getCurrentShift(now);
      if (shiftBadgeEl) shiftBadgeEl.innerHTML = getShiftBadgeHTML(shift);
      updateSidebarShift(shift, sidebarShiftEl);
    }
  }
  tick(); setInterval(tick, 1000);
}

function updateSidebarShift(shift, el) {
  if (!el) return;
  const dotCls = shift === 'morning' ? 'shift-morning' : 'shift-night';
  const label = shift === 'morning' ? 'Morning Shift' : 'Night Shift';
  const time = shift === 'morning' ? '10:00 вҖ“ 19:00' : '19:00 вҖ“ 10:00';
  el.innerHTML = `<div class="flex items-center gap-2">
    <span class="shift-dot ${dotCls}"></span>
    <div class="sidebar-logo-text"><div class="text-xs font-600 text-slate-900">${label}</div>
    <div class="text-xs text-slate-500">${time}</div></div></div>`;
}

