function togglePass() {
  const inp = document.getElementById('login-pass');
  const eye = document.getElementById('pass-eye');
  inp.type = inp.type === 'password' ? 'text' : 'password';
  eye.className = inp.type === 'password' ? 'fa-solid fa-eye text-sm' : 'fa-solid fa-eye-slash text-sm';
}

async function doLogin() {
  const u = document.getElementById('login-user').value.trim();
  const p = document.getElementById('login-pass').value;

  if (!u || !p) {
    showToast('Please enter both username and password', 'error');
    shakeInput();
    return;
  }

  const btn = document.querySelector('#login-screen button.btn-primary');
  const orgHtml = btn.innerHTML;
  btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Authenticating...';
  btn.disabled = true;

  try {
    // Update status UI in background
    checkBackendConnectionStatus();
    
    const data = await API.login(u, p);
    const now = new Date();
    const shift = getCurrentShift(now);

    currentUser = {
      id: data.id || null,
      name: data.name || 'User',
      username: data.username || '',
      role: data.role || 'user',
      token: data.token,
      loginTime: now.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' }),
      loginDate: getWorkingDate()
    };
    sessionShift = shift;  // Store shift at login

    LS.set('sf_current_session', currentUser);
    LS.set('sf_session_shift', shift);  // Persist shift for accidental logout recovery

    // Fetch data before letting them in
    btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Loading Data...';
    try {
      db_products = await API.request('/inventory/products', 'GET');
      db_entries = await API.getEntries();
    } catch (err) {
      console.error(err);
      // We continue even if empty, to not block login completely
    }

    document.getElementById('login-screen').classList.add('hidden');
    document.getElementById('app-shell').classList.remove('hidden');
    
    // Explicitly update all user-facing name displays immediately
    currentUser = LS.get('sf_current_session');
    buildSidebar();
    startClock();
    
    navigateTo(currentUser.role === 'admin' ? 'admin-home' : 'user-dashboard');
    showToast(`Welcome back, ${currentUser.name.split(' ')[0]}! ГғВ°Г…ВёГўвӮ¬ЛңГўвӮ¬В№`, 'success');
  } catch (error) {
    showToast(error.message, 'error');
    shakeInput();
  } finally {
    btn.innerHTML = orgHtml;
    btn.disabled = false;
  }
}

async function checkBackendConnectionStatus() {
  const statusEl = document.getElementById('connection-status');
  if (!statusEl) return true;

  statusEl.className = 'mb-4 text-xs rounded-lg border px-3 py-2 bg-slate-800/40 border-slate-700 text-slate-300';
  statusEl.innerHTML = '<i class="fa-solid fa-plug-circle-check mr-1"></i> Checking backend connectionвҖҰ';

  try {
    await API.request('/health', 'GET');
    statusEl.className = 'mb-4 text-xs rounded-lg border px-3 py-2 bg-emerald-500/10 border-emerald-500/30 text-emerald-300';
    statusEl.innerHTML = '<i class="fa-solid fa-circle-check mr-1"></i> Backend connected';
    return true;
  } catch (e) {
    statusEl.className = 'mb-4 text-xs rounded-lg border px-3 py-2 bg-red-500/10 border-red-500/30 text-red-300';
    statusEl.innerHTML = '<i class="fa-solid fa-triangle-exclamation mr-1"></i> Backend unreachable. Check API URL / server and try again.';
    return false;
  }
}

function shakeInput() {
  const card = document.querySelector('#login-screen .glass');
  card.style.animation = 'none';
  setTimeout(() => { card.style.animation = ''; card.classList.add('animate-slide-in'); }, 10);
}

document.addEventListener('keydown', e => {
  if (e.key === 'Enter' && !document.getElementById('login-screen').classList.contains('hidden')) doLogin();
});

