function renderPage(page) {
  switch (page) {
    case 'admin-home': return renderAdminHome();
    case 'admin-stock': return renderAdminStock();
    case 'admin-products': return renderAdminProducts();
    case 'admin-audit': return renderAdminAudit();
    case 'admin-analytics': return renderAdminAnalytics();
    case 'user-dashboard': return renderUserDashboard();
    case 'user-entries': return renderUserEntries();
    default: return '<p class="text-slate-500">Page not found.</p>';
  }
}

function getLowStockHTML() {
  const entries = db_entries;
  const products = db_products.filter(p => p.active);
  const lowStock = [];
  const LOW_STOCK_THRESHOLD_PCT = 35; // Threshold: 35% of historical max

  // Index entries by productId for O(E) pre-processing
  const entriesByProduct = {};
  entries.forEach(e => {
    if (!entriesByProduct[e.productId]) entriesByProduct[e.productId] = [];
    entriesByProduct[e.productId].push(e);
  });

  products.forEach(p => {
    const pEntries = entriesByProduct[p.id];
    if (!pEntries || pEntries.length === 0) return;

    // Sort entries by date/time to find latest
    const sortedEntries = [...pEntries].sort((a, b) => {
      const aDate = new Date(`${a.date}T${a.time || '00:00:00'}`);
      const bDate = new Date(`${b.date}T${b.time || '00:00:00'}`);
      if (bDate.getTime() !== aDate.getTime()) return bDate.getTime() - aDate.getTime();

      const aCreated = new Date(a.created_at || a.createdAt || 0).getTime();
      const bCreated = new Date(b.created_at || b.createdAt || 0).getTime();
      return bCreated - aCreated;
    });

    // Get latest entry with valid closing stock
    const latest = sortedEntries.find(e => e.closing !== null && e.closing !== undefined && Number(e.closing) > 0);
    if (!latest) return; // Skip if no valid closing stock found
    
    const currentStock = Number(latest.closing);

    // Calculate historical max from entries with valid closing values
    const validClosings = pEntries
      .map(e => Number(e.closing || 0))
      .filter(v => v > 0);
    
    if (validClosings.length === 0) return; // Skip if no valid historical data
    
    const maxHistorical = Math.max(...validClosings);
    const stockPercentage = Math.round((currentStock / maxHistorical) * 100);

    // Trigger alert if current stock is at or below the threshold percentage
    if (stockPercentage <= LOW_STOCK_THRESHOLD_PCT) {
      lowStock.push({ name: p.name, stock: currentStock, unit: p.unit, pct: stockPercentage });
    }
  });

  if (lowStock.length === 0) return '';

  lowStock.sort((a, b) => a.stock - b.stock);

  return `
    <div class="glass rounded-xl p-4 glow-red border border-red-600/40 animate-fade-in relative overflow-hidden" onclick="toggleLowStockExpand(event)">
      <div class="absolute right-0 top-0 w-32 h-32 bg-red-700/10 blur-3xl -z-10 rounded-full"></div>
      <div class="flex items-center gap-3 mb-3 relative z-10">
        <div class="w-10 h-10 rounded-xl bg-red-700/20 flex items-center justify-center text-red-600 border border-red-600/30 shadow-[0_0_15px_rgba(185,28,28,0.4)]">
          <i class="fa-solid fa-triangle-exclamation animate-pulse"></i>
        </div>
        <div class="flex-1">
          <div class="font-700 text-red-600 text-sm">Low Stock Alert (Threshold: 35%)</div>
          <div class="text-xs text-red-600/80 hidden md:block">The following items are below 35% of their historical maximum stock level.</div>
          <div class="text-xs text-red-600/80 md:hidden">${lowStock.length} item${lowStock.length > 1 ? 's' : ''} below threshold</div>
        </div>
        <button class="btn btn-ghost btn-sm p-1 md:hidden" onclick="toggleLowStockExpand(event)" title="Expand"><i class="fa-solid fa-chevron-down"></i></button>
      </div>
      <div class="low-stock-chips low-stock-brief md:low-stock-brief relative z-10">
        ${lowStock.map(p => `
          <span class="chip border-red-600/40 text-red-700 bg-red-700/10 shadow-sm text-nowrap" title="Historical Max: ${Math.round(p.stock / (p.pct / 100)) || '?'}">
            ${p.name}: <strong class="text-slate-900 ml-1">${p.stock}${p.unit.charAt(0) || ''} (${p.pct}%)</strong>
          </span>`).join('')}
      </div>
    </div>
  `;
}

function toggleLowStockExpand(e) {
  if (window.innerWidth < 768) {
    const section = e.currentTarget;
    const chips = section.querySelector('.low-stock-chips');
    chips?.classList.toggle('expanded');
    const btn = section.querySelector('button');
    if (btn) btn.innerHTML = chips?.classList.contains('expanded') 
      ? '<i class="fa-solid fa-chevron-up"></i>' 
      : '<i class="fa-solid fa-chevron-down"></i>';
  }
}

