let uePage = 1; const uePerPage = 10;
function renderUserEntriesTable() {
  const search = (document.getElementById('ue-search') || {}).value?.toLowerCase() || '';
  const date = (document.getElementById('ue-date') || {}).value || '';
  const shift = (document.getElementById('ue-shift') || {}).value || '';

  let rows = db_entries.filter(e => {
    if (e.userId !== currentUser.id) return false;
    if (search && !e.productName.toLowerCase().includes(search)) return false;
    if (date && e.date !== date) return false;
    if (shift && e.shift !== shift) return false;
    return true;
  });

  const count = document.getElementById('ue-count');
  if (count) count.textContent = `${rows.length} entries`;

  const totalPages = Math.ceil(rows.length / uePerPage) || 1;
  if (uePage > totalPages) uePage = 1;
  const paged = rows.slice((uePage - 1) * uePerPage, uePage * uePerPage);

  const tbody = document.getElementById('ue-tbody');
  if (tbody) tbody.innerHTML = paged.map(e => `
    <tr>
      <td class="mono text-xs font-600">${e.date}</td>
      <td class="font-500 text-slate-900">${e.productName}</td>
      <td class="mono">${e.opening}</td>
      <td class="mono">${e.received}</td>
      <td class="mono ${Number(e.disbursed || 0) > 0 ? 'text-brand' : ''}">${e.disbursed || 0}</td>
      <td class="mono ${Number(e.damaged) > 0 ? 'text-red-400' : ''}">${e.damaged}</td>
      <td class="mono">${e.closing}</td>
      <td class="mono font-600 text-slate-900">${e.total}</td>
      <td class="mono ${Number(e.variance) !== 0 ? 'text-amber-400 font-600' : ''}">${e.variance}</td>
      <td>${getShiftBadgeHTML(e.shift)}</td>
      <td class="mono text-xs text-slate-500">${e.time}</td>
    </tr>`).join('') || '<tr><td colspan="11" class="text-center text-slate-500 py-10">No entries found</td></tr>';

  const pg = document.getElementById('ue-pagination');
  if (pg) pg.innerHTML = paginationHTML(uePage, totalPages, 'uePage', 'renderUserEntriesTable');
}

// в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬ PAGE INIT (called after render) в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬
function initPage(page) {
  if (page === 'admin-stock') { asPage = 1; renderAdminStockTable(); }
  if (page === 'admin-products') { renderProductTable(); }
  if (page === 'admin-audit') { renderAuditTable(); }
  if (page === 'user-entries') { uePage = 1; renderUserEntriesTable(); }
  // Update form time tag every minute
  if (page === 'user-dashboard') {
    setInterval(() => {
      const el = document.getElementById('form-time-tag');
      if (el) el.textContent = new Date().toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' });
    }, 30000);
  }
}

// в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬ PAGINATION в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬
function paginationHTML(current, total, varName, fn) {
  if (total <= 1) return '';
  const pages = [];
  for (let i = 1; i <= total; i++) {
    if (i === 1 || i === total || Math.abs(i - current) <= 1) pages.push(i);
    else if (pages[pages.length - 1] !== 'вҖҰ') pages.push('вҖҰ');
  }
  return `
  <div class="flex items-center gap-2 text-sm">
    <span class="text-slate-500">Page ${current} of ${total}</span>
    <div class="flex gap-1 ml-auto">
      <button onclick="${varName}=${current}-1;${fn}()" ${current <= 1 ? 'disabled' : ''} class="btn btn-secondary btn-sm"><i class="fa-solid fa-chevron-left text-xs"></i></button>
      ${pages.map(p => p === 'вҖҰ' ? `<span class="btn btn-ghost btn-sm">вҖҰ</span>` :
    `<button onclick="${varName}=${p};${fn}()" class="btn ${p === current ? 'btn-primary' : 'btn-ghost'} btn-sm">${p}</button>`).join('')}
      <button onclick="${varName}=${current}+1;${fn}()" ${current >= total ? 'disabled' : ''} class="btn btn-secondary btn-sm"><i class="fa-solid fa-chevron-right text-xs"></i></button>
    </div>
  </div>`;
}

