function showConfirm(title, msg, cb, icon = 'fa-triangle-exclamation', iconBg = 'rgba(239,68,68,.1)', iconColor = '#f87171') {
  document.getElementById('confirm-title').textContent = title;
  document.getElementById('confirm-msg').textContent = msg;
  document.getElementById('confirm-icon').innerHTML = `<i class="fa-solid ${icon} text-2xl" style="color:${iconColor}"></i>`;
  document.getElementById('confirm-icon').style.background = iconBg;
  document.getElementById('confirm-ok').onclick = () => { closeConfirm(); cb(); };
  document.getElementById('confirm-dialog').classList.remove('hidden');
}
function closeConfirm() { document.getElementById('confirm-dialog').classList.add('hidden'); }
document.getElementById('confirm-dialog').addEventListener('click', e => {
  if (e.target === document.getElementById('confirm-dialog')) closeConfirm();
});

// в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬ TOAST в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬
function showToast(msg, type = 'info', duration = 3500) {
  const icons = { success: 'fa-circle-check', error: 'fa-circle-xmark', warn: 'fa-triangle-exclamation', info: 'fa-circle-info' };
  const container = document.getElementById('toast-container');
  const toast = document.createElement('div');
  toast.className = `toast toast-${type} animate-toast-in`;
  toast.innerHTML = `<i class="fa-solid ${icons[type] || icons.info}"></i><span class="flex-1">${msg}</span>
    <button onclick="this.parentElement.remove()" class="opacity-50 hover:opacity-100 transition-opacity ml-1"><i class="fa-solid fa-xmark text-xs"></i></button>`;
  container.appendChild(toast);
  setTimeout(() => { toast.classList.add('animate-toast-out'); setTimeout(() => toast.remove(), 300); }, duration);
}

// в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬ INITIALIZATION в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬в”ҖГўвӮ¬ВқГўвҖҡВ¬
async function initApp() {
  const session = LS.get('sf_current_session');
  const token = API.getToken();
  const savedShift = LS.get('sf_session_shift');

  const splash = document.getElementById('loading-splash');

  if (session && session.id && token) {
    currentUser = session;
    sessionShift = savedShift;  // Restore shift from previous session

    // Ensure sidebar is built with the session name before showing the app
    buildSidebar();
    
    // Show app immediately with any cached data
    document.getElementById('login-screen').classList.add('hidden');
    document.getElementById('app-shell').classList.remove('hidden');
    startClock();
    navigateTo(currentUser.role === 'admin' ? 'admin-home' : 'user-dashboard');

    // FIX 1: Always force a fresh data sync in the background after session restore
    // This ensures data from a new session appears without requiring re-login.
    try {
      const [freshProducts, freshEntries] = await Promise.all([
        API.request('/inventory/products', 'GET'),
        API.getEntries()
      ]);
      const dataChanged = JSON.stringify(freshEntries) !== JSON.stringify(db_entries) ||
                          JSON.stringify(freshProducts) !== JSON.stringify(db_products);
      db_products = freshProducts;
      db_entries = freshEntries;
      if (dataChanged) {
        // Re-render current page silently to show fresh data
        navigateTo(activePage, true);
      }
    } catch (e) {
      console.warn('Background session sync failed:', e.message);
    } finally {
      if (splash) splash.classList.add('hidden');
    }
  } else {
    // Show login screen if no session
    if (splash) splash.classList.add('hidden');
    document.getElementById('login-screen').classList.remove('hidden');
    document.getElementById('app-shell').classList.add('hidden');
    
    // Check connection but don't await, let it happen in background
    checkBackendConnectionStatus();
  }
}

// Start app
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', initApp);
} else {
  initApp();
}
